sql:
SELECT AVG(average_response_time) AS avg_response_time
FROM session_statistics
WHERE player_id = '1';

SELECT COUNT(action_id) AS total_actions
FROM session_actions
WHERE session_id = '0';

SELECT action_type, COUNT(action_type) AS total_actions
FROM session_actions
GROUP BY action_type;

SELECT action_type
FROM session_actions
WHERE session_id = '0';

external_knowledge:
; Engagement levels are determined by the following rules:
- Highly Engaged: Cumulative score > 100 and average session rating > 3;
- Engaged: Cumulative score > 50 and average session rating > 3;
- Low Engagement: Cumulative score < 50 and average session rating < 3;
- Neutral Engagement: All other cases.
; The purpose of excluding the first session is to allow new players to adjust and to focus on their performance trends over time.

sql:
SELECT player_id, AVG(average_response_time) AS avg_response_time, SUM(total_responses) AS total_responses
FROM session_statistics
GROUP BY player_id;

SELECT player_id, SUM(total_rounds_played) AS total_rounds
FROM session_players
GROUP BY player_id;

SELECT MAX(total_time_spent) AS max_time_spent
   FROM (
       SELECT player_id, SUM(time) AS total_time_spent
       FROM session_actions
       GROUP BY player_id
   ) AS player_times;
